      code: '# A VPC with a deliberately non-overlapping range\nresource "aws_vpc" "prod" {\n  cidr_block           = "10.20.0.0/16"   # shared-svc uses 10.10/16\n  enable_dns_support   = true\n  enable_dns_hostnames = true\n  tags = { Name = "prod", Environment = "prod" }\n}\n\n# Flow logs for security + connectivity debugging\nresource "aws_flow_log" "prod" {\n  vpc_id          = aws_vpc.prod.id\n  traffic_type    = "ALL"\n  log_destination = aws_cloudwatch_log_group.flow.arn\n}',
